486	func (r *Reconciler) getIssuer(istiocsr *v1alpha1.IstioCSR) (client.Object, error) {
487		issuerRefKind := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Kind)
488		key := client.ObjectKey{
489			Name:      istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Name,
490			Namespace: istiocsr.Spec.IstioCSRConfig.Istio.Namespace,
491		}
492	
493		var object client.Object
494		switch issuerRefKind {
495		case clusterIssuerKind:
496			object = &certmanagerv1.ClusterIssuer{}
497		case issuerKind:
498			object = &certmanagerv1.Issuer{}
499		}
500	
501		if err := r.Get(r.ctx, key, object); err != nil {
502			return nil, fmt.Errorf("failed to fetch %q issuer: %w", key, err)
503		}
504		return object, nil
505	}
