507	func (r *Reconciler) createCAConfigMapFromIstiodCertificate(istiocsr *v1alpha1.IstioCSR, resourceLabels map[string]string) error {
508		istiodCertificate, err := r.getCertificateObject(istiocsr, resourceLabels)
509		if err != nil {
510			return common.FromClientError(err, "failed to fetch istiod certificate")
511		}
512	
513		secretKey := client.ObjectKey{
514			Name:      istiodCertificate.Spec.SecretName,
515			Namespace: istiodCertificate.GetNamespace(),
516		}
517		secret := &corev1.Secret{}
518		if err := r.Get(r.ctx, secretKey, secret); err != nil {
519			return fmt.Errorf("failed to fetch secret in issuer: %w", err)
520		}
521		if err := r.updateWatchLabel(secret, istiocsr); err != nil {
522			return err
523		}
524	
525		certData := string(secret.Data[IstiocsrCAKeyName])
526		return r.createOrUpdateCAConfigMap(istiocsr, certData, resourceLabels)
527	}
