529	func (r *Reconciler) createCAConfigMapFromIssuerSecret(istiocsr *v1alpha1.IstioCSR, issuerConfig certmanagerv1.IssuerConfig, resourceLabels map[string]string) error {
530		if issuerConfig.CA.SecretName == "" {
531			return fmt.Errorf("failed to fetch CA certificate configured for the %s issuer of CA type", istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Name)
532		}
533	
534		secretKey := client.ObjectKey{
535			Name:      issuerConfig.CA.SecretName,
536			Namespace: istiocsr.Spec.IstioCSRConfig.Istio.Namespace,
537		}
538		secret := &corev1.Secret{}
539		if err := r.Get(r.ctx, secretKey, secret); err != nil {
540			return fmt.Errorf("failed to fetch secret in issuer: %w", err)
541		}
542		if err := r.updateWatchLabel(secret, istiocsr); err != nil {
543			return err
544		}
545	
546		certData := string(secret.Data[IstiocsrCAKeyName])
547		return r.createOrUpdateCAConfigMap(istiocsr, certData, resourceLabels)
548	}
