237	
238		var objectModified bool
239		switch desiredObj := desired.(type) {
240		case *certmanagerv1.Certificate:
241			fetchedCert, ok := fetched.(*certmanagerv1.Certificate)
242			if !ok {
243				panic("failed to convert fetched to *certmanagerv1.Certificate")
244			}
245			objectModified = certificateSpecModified(desiredObj, fetchedCert)
246		case *rbacv1.ClusterRole:
247			fetchedClusterRole, ok := fetched.(*rbacv1.ClusterRole)
248			if !ok {
249				panic("failed to convert fetched to *rbacv1.ClusterRole")
250			}
251			objectModified = rbacRoleRulesModified(desiredObj, fetchedClusterRole)
252		case *rbacv1.ClusterRoleBinding:
253			fetchedClusterRoleBinding, ok := fetched.(*rbacv1.ClusterRoleBinding)
254			if !ok {
255				panic("failed to convert fetched to *rbacv1.ClusterRoleBinding")
256			}
257			objectModified = rbacRoleBindingRefModified(desiredObj, fetchedClusterRoleBinding) ||
258				rbacRoleBindingSubjectsModified(desiredObj, fetchedClusterRoleBinding)
259		case *appsv1.Deployment:
260			fetchedDeployment, ok := fetched.(*appsv1.Deployment)
261			if !ok {
262				panic("failed to convert fetched to *appsv1.Deployment")
263			}
264			objectModified = deploymentSpecModified(desiredObj, fetchedDeployment)
265		case *rbacv1.Role:
266			fetchedRole, ok := fetched.(*rbacv1.Role)
267			if !ok {
268				panic("failed to convert fetched to *rbacv1.Role")
269			}
270			objectModified = rbacRoleRulesModified(desiredObj, fetchedRole)
271		case *rbacv1.RoleBinding:
272			fetchedRoleBinding, ok := fetched.(*rbacv1.RoleBinding)
273			if !ok {
274				panic("failed to convert fetched to *rbacv1.RoleBinding")
275			}
276			objectModified = rbacRoleBindingRefModified(desiredObj, fetchedRoleBinding) ||
277				rbacRoleBindingSubjectsModified(desiredObj, fetchedRoleBinding)
278		case *corev1.Service:
279			fetchedService, ok := fetched.(*corev1.Service)
280			if !ok {
281				panic("failed to convert fetched to *corev1.Service")
282			}
