308	func deploymentSpecModified(desired, fetched *appsv1.Deployment) bool {
309		// check just the fields which are set by the controller and set in static manifest,
310		// as fields with default values end up in manifest and causes plain check to fail.
311		if *desired.Spec.Replicas != *fetched.Spec.Replicas ||
312			!reflect.DeepEqual(desired.Spec.Selector.MatchLabels, fetched.Spec.Selector.MatchLabels) {
313			return true
314		}
315	
316		if !reflect.DeepEqual(desired.Spec.Template.Labels, fetched.Spec.Template.Labels) ||
317			len(desired.Spec.Template.Spec.Containers) != len(fetched.Spec.Template.Spec.Containers) {
318			return true
319		}
320	
321		desiredContainer := desired.Spec.Template.Spec.Containers[0]
322		fetchedContainer := fetched.Spec.Template.Spec.Containers[0]
323		if !reflect.DeepEqual(desiredContainer.Args, fetchedContainer.Args) ||
324			desiredContainer.Name != fetchedContainer.Name || desiredContainer.Image != fetchedContainer.Image ||
325			desiredContainer.ImagePullPolicy != fetchedContainer.ImagePullPolicy {
326			return true
327		}
328	
329		if len(desiredContainer.Ports) != len(fetchedContainer.Ports) {
330			return true
331		}
332		for _, fetchedPort := range fetchedContainer.Ports {
333			matched := false
334			for _, desiredPort := range desiredContainer.Ports {
335				if fetchedPort.ContainerPort == desiredPort.ContainerPort {
336					matched = true
337					break
338				}
339			}
340			if !matched {
341				return true
342			}
343		}
344	
345		if desiredContainer.ReadinessProbe.HTTPGet.Path != fetchedContainer.ReadinessProbe.HTTPGet.Path ||
346			desiredContainer.ReadinessProbe.InitialDelaySeconds != fetchedContainer.ReadinessProbe.InitialDelaySeconds ||
347			desiredContainer.ReadinessProbe.PeriodSeconds != fetchedContainer.ReadinessProbe.PeriodSeconds {
348			return true
349		}
350	
351		if !reflect.DeepEqual(desiredContainer.Resources, fetchedContainer.Resources) ||
352			!reflect.DeepEqual(*desiredContainer.SecurityContext, *fetchedContainer.SecurityContext) ||
353			!reflect.DeepEqual(desiredContainer.VolumeMounts, fetchedContainer.VolumeMounts) {
354			return true
355		}
356	
357		if desired.Spec.Template.Spec.ServiceAccountName != fetched.Spec.Template.Spec.ServiceAccountName ||
358			!reflect.DeepEqual(desired.Spec.Template.Spec.NodeSelector, fetched.Spec.Template.Spec.NodeSelector) ||
359			!reflect.DeepEqual(desired.Spec.Template.Spec.Volumes, fetched.Spec.Template.Spec.Volumes) {
360			return true
361		}
362	
363		return false
364	}
