443			desiredRoleBinding, ok := any(desired).(*rbacv1.RoleBinding)
444			if !ok {
445				panic("failed to convert desired to *rbacv1.RoleBinding")
446			}
447			fetchedRoleBinding, ok := any(fetched).(*rbacv1.RoleBinding)
448			if !ok {
449				panic("failed to convert fetched to *rbacv1.RoleBinding")
450			}
451			return !reflect.DeepEqual(desiredRoleBinding.Subjects, fetchedRoleBinding.Subjects)
452		default:
453			panic(fmt.Sprintf("unsupported object type %v", typ))
454		}
455	}
