482		if err := r.updateStatus(r.ctx, istiocsr); err != nil {
483			errUpdate := fmt.Errorf("failed to update %s/%s status: %w", istiocsr.GetNamespace(), istiocsr.GetName(), err)
484			if prependErr != nil {
