291	// GenerateCertificate creates a certificate with specified tweaks.
292	func GenerateCertificate(commonName string, organization []string, tweak CertificateTweak) string {
293		// Generate RSA private key
294		privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
295		if err != nil {
296			panic(fmt.Sprintf("Failed to generate private key: %v", err))
297		}
298	
299		template := &x509.Certificate{
300			Subject: pkix.Name{
301				CommonName:   commonName,
302				Organization: organization,
303			},
304			NotBefore:             time.Now(),
305			NotAfter:              time.Now().Add(24 * time.Hour),
306			KeyUsage:              x509.KeyUsageKeyEncipherment | x509.KeyUsageDigitalSignature,
307			ExtKeyUsage:           []x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth},
308			BasicConstraintsValid: true,
309			IsCA:                  false,
310		}
311	
312		// Apply tweaks to modify the template
313		tweak(template)
314	
315		certDER, err := x509.CreateCertificate(rand.Reader, template, template, &privateKey.PublicKey, privateKey)
316		if err != nil {
317			panic(fmt.Sprintf("Failed to create certificate: %v", err))
318		}
319	
320		// Encode certificate to PEM format
321		certPEM := pem.EncodeToMemory(&pem.Block{
322			Type:  "CERTIFICATE",
323			Bytes: certDER,
324		})
325	
326		return string(certPEM)
327	}
