	// Predicate that matches the CNO-injected CA bundle ConfigMap in the operator namespace.
	// This ConfigMap is NOT managed by the istiocsr controller (no managed label) but we need
	// to detect when CNO updates the trusted CA bundle so we can recompute the hash and
	// trigger a rolling restart of the IstioCSR deployment.
	injectedCABundleConfigMapPredicate := predicate.Funcs{
		CreateFunc: func(e event.CreateEvent) bool {
			return e.Object.GetNamespace() == common.OperatorNamespace &&
				e.Object.GetName() == common.TrustedCABundleConfigMapName
		},
		UpdateFunc: func(e event.UpdateEvent) bool {
			return e.ObjectNew.GetNamespace() == common.OperatorNamespace &&
				e.ObjectNew.GetName() == common.TrustedCABundleConfigMapName
		},
		DeleteFunc: func(e event.DeleteEvent) bool {
			return e.Object.GetNamespace() == common.OperatorNamespace &&
				e.Object.GetName() == common.TrustedCABundleConfigMapName
		},
		GenericFunc: func(e event.GenericEvent) bool {
			return e.Object.GetNamespace() == common.OperatorNamespace &&
				e.Object.GetName() == common.TrustedCABundleConfigMapName
		},
	}

	// Map function for the CNO-injected CA bundle ConfigMap. Since this ConfigMap
	// lacks the managed labels used by the main mapFunc, it uses a dedicated mapper
	// that enqueues reconcile requests for all existing IstioCSR instances.
	caConfigMapMapFunc := func(ctx context.Context, obj client.Object) []reconcile.Request {
		r.log.V(4).Info("received CA bundle ConfigMap event",
			"name", obj.GetName(), "namespace", obj.GetNamespace())
		istiocsrList := &v1alpha1.IstioCSRList{}
		if err := r.List(ctx, istiocsrList); err != nil {
			r.log.Error(err, "failed to list IstioCSR instances for CA bundle ConfigMap event")
			return nil
		}
		var requests []reconcile.Request
		for _, item := range istiocsrList.Items {
			requests = append(requests, reconcile.Request{
				NamespacedName: types.NamespacedName{
					Name:      item.GetName(),
					Namespace: item.GetNamespace(),
				},
			})
		}
		return requests
	}
