## New file: `pkg/controller/istiocsr/configmaps.go`

```go
package istiocsr

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"

	corev1 "k8s.io/api/core/v1"
	"sigs.k8s.io/controller-runtime/pkg/client"

	"github.com/openshift/cert-manager-operator/pkg/controller/common"
)

// readCABundleHash reads the CNO-injected CA bundle ConfigMap from the operator
// namespace, computes a SHA-256 hash of the PEM content, and returns it.
// Returns ("", nil) when the ConfigMap exists but the CA bundle key is absent
// or empty (e.g. CNO has not yet injected the bundle).
func (r *Reconciler) readCABundleHash() (string, error) {
	injectionCM := &corev1.ConfigMap{}
	key := client.ObjectKey{
		Namespace: common.OperatorNamespace,
		Name:      common.TrustedCABundleConfigMapName,
	}
	if err := r.Get(r.ctx, key, injectionCM); err != nil {
		return "", common.FromClientError(
			err,
			"failed to read CA bundle ConfigMap %q in namespace %q",
			common.TrustedCABundleConfigMapName, common.OperatorNamespace,
		)
	}

	caBundle, ok := injectionCM.Data[common.TrustedCABundleKey]
	if !ok || caBundle == "" {
		r.log.V(4).Info("CA bundle ConfigMap exists but key is absent or empty, skipping hash",
			"configmap", fmt.Sprintf("%s/%s", common.OperatorNamespace, common.TrustedCABundleConfigMapName),
			"key", common.TrustedCABundleKey)
		return "", nil
	}

	return computeCABundleHash(caBundle), nil
}

// computeCABundleHash returns the SHA-256 hex digest of the CA bundle PEM content.
func computeCABundleHash(caBundle string) string {
	hash := sha256.Sum256([]byte(caBundle))
	return hex.EncodeToString(hash[:])
}
