// stampCABundleHashAnnotation sets the CA bundle hash annotation on the
// deployment's pod template spec to trigger rolling restarts when the
// CA bundle content changes.
func stampCABundleHashAnnotation(deployment *appsv1.Deployment, caBundleHash string) {
	if caBundleHash == "" {
		return
	}
	if deployment.Spec.Template.Annotations == nil {
		deployment.Spec.Template.Annotations = make(map[string]string)
	}
	deployment.Spec.Template.Annotations[caBundleHashAnnotation] = caBundleHash
}
```

